package com.taxin60sec.backend.service.impl;
import com.taxin60sec.backend.common.ApiErrorCode; import com.taxin60sec.backend.dto.business.*; import com.taxin60sec.backend.entity.*; import com.taxin60sec.backend.exception.ApiException; import com.taxin60sec.backend.mapper.BusinessProfileMapper; import com.taxin60sec.backend.repository.*; import com.taxin60sec.backend.service.BusinessProfileService; import jakarta.transaction.Transactional; import org.springframework.http.HttpStatus; import org.springframework.stereotype.Service; import java.util.List;
@Service @Transactional public class BusinessProfileServiceImpl implements BusinessProfileService { private final BusinessProfileRepository businesses;private final ClientProfileRepository clients;private final UserRepository users;private final BusinessProfileMapper mapper; public BusinessProfileServiceImpl(BusinessProfileRepository businesses,ClientProfileRepository clients,UserRepository users,BusinessProfileMapper mapper){this.businesses=businesses;this.clients=clients;this.users=users;this.mapper=mapper;} public BusinessProfileResponse createBusiness(BusinessProfileRequest r){BusinessProfile b=new BusinessProfile();apply(b,r);return mapper.toResponse(businesses.save(b));} public BusinessProfileResponse updateBusiness(Long id,BusinessProfileRequest r){BusinessProfile b=find(id);apply(b,r);return mapper.toResponse(b);} public void deleteBusiness(Long id){find(id).markDeleted();} public BusinessProfileResponse getBusiness(Long id){return mapper.toResponse(find(id));} public List<BusinessProfileResponse> getBusinessesForClient(Long clientId){return businesses.findByClientProfileIdAndDeletedFalse(clientId).stream().map(mapper::toResponse).toList();} private BusinessProfile find(Long id){return businesses.findById(id).filter(b->!b.isDeleted()).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ApiErrorCode.NOT_FOUND,"Business profile not found"));} private void apply(BusinessProfile b,BusinessProfileRequest r){b.setClientProfile(clients.findById(r.clientProfileId()).filter(c->!c.isDeleted()).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ApiErrorCode.NOT_FOUND,"Client profile not found")));b.setAssignedCA(users.findById(r.assignedCaId()).filter(u->!u.isDeleted()).orElseThrow(()->new ApiException(HttpStatus.NOT_FOUND,ApiErrorCode.NOT_FOUND,"Assigned CA not found")));b.setBusinessName(r.businessName());b.setBusinessType(r.businessType());b.setPanNumber(r.panNumber());b.setGstin(r.gstin());b.setTanNumber(r.tanNumber());b.setCin(r.cin());b.setMsmeNumber(r.msmeNumber());b.setIncorporationDate(r.incorporationDate());b.setBusinessStatus(r.businessStatus());b.setAddress(r.address());} }
